import { Expression, Identifier } from '../../../../../node/base.js'
import { Block } from '../../../../../node/block.js'
import { DeclareClass } from '../../../../../node/class.js'
import { EOL } from '../../../../../node/misc.js'
import { type Token } from '../../../../tokenize/token.js'
import { PatternUnit, Rule } from '../../../type.js'
import { parseClassHeaderTokens } from './class-header.js'

const PREFIX: PatternUnit[] = [
    {
        type: Identifier,
        value: '클래스',
    },
    {
        type: Expression,
        value: ',',
    },
]

const SUFFIX: PatternUnit[] = [
    {
        type: EOL,
    },
    {
        type: Block,
    },
]

export function tokensToClassDeclareRule(headerTokens: Token[]): Rule {
    const { name, parentName, inheritanceStyle } =
        parseClassHeaderTokens(headerTokens)

    const pattern: PatternUnit[] = [
        ...PREFIX,
        {
            type: Identifier,
            value: name,
        },
        ...(parentName
            ? inheritanceStyle === 'parenthesis'
                ? ([
                      {
                          type: Expression,
                          value: '(',
                      },
                      {
                          type: Identifier,
                          value: parentName,
                      },
                      {
                          type: Expression,
                          value: ')',
                      },
                  ] as PatternUnit[])
                : ([
                      {
                          type: Expression,
                          value: ',',
                      },
                      {
                          type: Identifier,
                          value: parentName,
                      },
                  ] as PatternUnit[])
            : []),
        ...SUFFIX,
    ]

    return {
        pattern,
        factory: (nodes, matchedNodes) => {
            const body = nodes[nodes.length - 1] as Block
            return new DeclareClass(name, body, matchedNodes, parentName)
        },
    }
}
